CREATE TABLE Manufacturing_Data (
    ProductionID VARCHAR(20) PRIMARY KEY,
    ProductionDate DATE,
    ProductCategory VARCHAR(50),
    ProductName VARCHAR(100),
    Plant VARCHAR(100),
    Machine VARCHAR(50),
    Shift VARCHAR(20),
    QuantityProduced INT,
    DefectiveQuantity INT,
    ProductionCost INT,
    Revenue INT,
    City VARCHAR(50),
    Month VARCHAR(20)
);



